502	
503	        const blockType = blockTypeRegistry.get(engine.block.type);
504	        if (!blockType) continue; // Type was unregistered after block was created; skip
505	
506	        // Poll interval throttle
507	        if (blockType.pollIntervalMs !== undefined && engine.block.lastCheckedAt) {
508	          const elapsed = Date.now() - new Date(engine.block.lastCheckedAt).getTime();
509	          if (elapsed < blockType.pollIntervalMs) continue;
510	        }
511	
512	        let result: CheckResult;
513	        try {
514	          result = await blockType.check(engine.block.condition);
515	        } catch (err) {
516	          // Log warning, skip — engine stays blocked, retry next cycle
517	          console.warn(
518	            `Block checker "${engine.block.type}" threw for engine "${engine.id}" in rig "${rig.id}":`,
519	            err,
520	          );
521	          continue;
522	        }
523	
524	        if (result.status === 'failed') {
525	          // Permanent failure — fail the engine and rig immediately
526	          const message = result.reason
527	            ? `Block "${engine.block.type}" failed: ${result.reason}`
528	            : `Block "${engine.block.type}" failed permanently`;
529	          await failEngine(rig, engine.id, message);
530	          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
531	        }
532	
533	        if (result.status !== 'cleared') {
534	          // Pending (or any unexpected status) — update lastCheckedAt and continue checking other engines
535	          const now = new Date().toISOString();
536	          const updatedEngines = rig.engines.map((e) =>
537	            e.id === engine.id
538	              ? { ...e, block: { ...e.block!, lastCheckedAt: now } }
539	              : e,
540	          );
541	          await rigsBook.patch(rig.id, { engines: updatedEngines });
542	          continue; // Check next engine
543	        }
544	
545	        // Cleared — store block record in memory for priorBlock, then transition engine to pending
546	        const priorBlockRecord = engine.block;
547	        pendingPriorBlocks.set(`${rig.id}:${engine.id}`, priorBlockRecord);
548	
549	        const updatedEngines = rig.engines.map((e) =>
550	          e.id === engine.id
551	            ? { ...e, status: 'pending' as const, block: undefined }
552	            : e,
553	        );
554	
555	        // Restore rig to running if it was blocked; use isRigBlocked on updatedEngines
556	        // (always false after unblocking, but keeps call sites consistent per R13)
557	        const stillBlocked = isRigBlocked(updatedEngines);
558	        const rigStatus = stillBlocked ? 'blocked' : 'running';
559	
560	        await rigsBook.patch(rig.id, {
561	          engines: updatedEngines,
562	          status: rigStatus,
563	        });
564	
565	        return { action: 'engine-unblocked', rigId: rig.id, engineId: engine.id };
566	      }
567	    }
568	    return null;
569	  }
570	
571	  /**
572	   * Phase 3 — run.
573	   *
574	   * Find the first pending engine in any running rig whose upstream is
575	   * all completed. Execute it:
576	   * - Clockwork ('completed') → store yields, mark engine completed,
577	   *   check for rig completion.
