98	/** Create a started Loom and return its API plus event emitter for testing. */
99	function startLoom(eventHandlers?: Map<string, ((...args: unknown[]) => void)[]>): LoomApi {
100	  const plugin = createLoom();
101	  const apparatus = (plugin as { apparatus: { start: (ctx: unknown) => void; provides: unknown } }).apparatus;
102	  const handlers = eventHandlers ?? new Map();
103	  apparatus.start({
104	    on(event: string, handler: (...args: unknown[]) => void) {
105	      if (!handlers.has(event)) handlers.set(event, []);
106	      handlers.get(event)!.push(handler);
107	    },
108	  });
109	  return apparatus.provides as LoomApi;
110	}
