// Scan apparatus supportKits via plugin:initialized:
const handlers = new Map<...>();
const api = startLoom(handlers);
emitPluginInitialized(handlers, makeLoadedApparatus('my-apparatus', '@test/my-apparatus', { roles: { ... } }));
